def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 5:
            for x in range(5, 0, -1):
                penalty = ((ratio - x) ** 4) / (x**2 + 1)
                priority += penalty ** 0.5
            priority += np.exp(ratio - 5) * np.log1p(ratio)
        elif 3 < ratio <= 5:
            for m in range(1, int(np.ceil(ratio)) + 2):
                priority += np.sin(ratio * m) * np.cos(m / (ratio + 0.1)) * ((ratio - m) ** 2)
            priority += np.log(ratio) * 7 - np.sqrt(ratio)
        elif 2 <= ratio <= 3:
            s1 = 0
            for k in range(1, 4):
                s1 += np.tanh((ratio - k) * 3) / k
            s2 = 0
            for j in range(1, 6):
                s2 += ((2.5 - ratio) ** j) / (j * 1.5)
            priority = s1 * 5 + s2 * np.exp(-ratio / 2)
        elif 1 <= ratio < 2:
            priority = -np.log(ratio) * 4 + np.sin(ratio * 10) * np.tanh(3 * (2 - ratio))
            if (i + 1) % 2 == 0:
                priority += np.sqrt(bin_cap) / (ratio + 1)
            else:
                priority -= np.sqrt(bin_cap) / (ratio + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 7):
                s += ((1 - ratio) ** n) / (n + 0.5)
            priority = s * np.cos(5 * ratio) + np.log1p(bin_cap) * np.sin(ratio * 4)
            if bin_cap < item:
                priority += (item - bin_cap) ** 2 / (bin_cap + 1)
            else:
                priority -= np.tanh(bin_cap / (item + 0.1))
        else:
            sum_k = 0
            for k in range(1, 8):
                sum_k += ((0.5 - ratio) ** k) / (k + 1) ** 2
            priority = sum_k + 1 / (bin_cap + 1)
            if item % 3 == 0:
                priority *= 2 - np.cos(bin_cap)
            elif item % 3 == 1:
                priority /= 2 + np.sin(bin_cap)
            else:
                priority += np.exp(-bin_cap / (item + 1))
        if bin_cap < item * 0.3:
            priority += np.log1p(item * bin_cap) * 3
            priority += np.sum([np.sin(bin_cap / (n + 1)) for n in range(3)])
        elif bin_cap > item * 4:
            priority -= np.exp(-ratio) * np.sum([np.cos(ratio * n) / (n + 1) for n in range(5)])
        elif item * 0.8 < bin_cap < item * 1.2:
            priority *= np.tanh(bin_cap / (item + 0.1))
            for z in range(1, 4):
                priority += ((ratio - 1) ** z) * np.sin(bin_cap * z)
        priorities[i] = priority
    return priorities
